-- Migration: Improve Rate Limits Table for Persistent Rate Limiting -- This migration adds proper columns for the new rate limiting system -- Run this in your Supabase SQL editor -- Drop existing table if exists and recreate with proper structure DROP TABLE IF EXISTS rate_limits; CREATE TABLE rate_limits ( ip TEXT PRIMARY KEY, request_count INTEGER DEFAULT 1, first_request_time TIMESTAMPTZ DEFAULT NOW(), last_request_time TIMESTAMPTZ DEFAULT NOW(), blocked_until TIMESTAMPTZ NULL, created_at TIMESTAMPTZ DEFAULT NOW(), updated_at TIMESTAMPTZ DEFAULT NOW() ); -- Add comment on table COMMENT ON TABLE rate_limits IS 'Persistent rate limiting table for contact form submissions. Tracks IP-based request counts and blocks abusive IPs.'; -- Create index for faster lookups CREATE INDEX idx_rate_limits_ip ON rate_limits(ip); CREATE INDEX idx_rate_limits_blocked ON rate_limits(blocked_until) WHERE blocked_until IS NOT NULL; -- Create function to automatically clean old records CREATE OR REPLACE FUNCTION clean_old_rate_limits() RETURNS void AS $$ BEGIN DELETE FROM rate_limits WHERE first_request_time < NOW() - INTERVAL '24 hours' AND blocked_until IS NULL; END; $$ LANGUAGE plpgsql; -- Create cron extension if not exists (requires Supabase dashboard enable) -- CREATE EXTENSION IF NOT EXISTS pg_cron; -- Schedule cleanup every hour (uncomment after enabling pg_cron) -- SELECT cron.schedule('clean-rate-limits', '0 * * * *', 'SELECT clean_old_rate_limits();'); -- Grant proper permissions ALTER TABLE rate_limits ENABLE ROW LEVEL SECURITY; -- Create policy to allow service role full access CREATE POLICY "Service role can manage rate limits" ON rate_limits FOR ALL TO service_role USING (true) WITH CHECK (true); -- Create policy to deny public access (rate limits should only be accessed via serverless functions) CREATE POLICY "Public cannot access rate limits" ON rate_limits FOR ALL TO public USING (false) WITH CHECK (false); -- Insert a test record to verify structure (optional, can be removed) -- INSERT INTO rate_limits (ip, request_count) VALUES ('test-ip-placeholder', 0); -- Note: In production, you may want to: -- 1. Add additional columns like user_agent, country_code for better analysis -- 2. Add composite index if querying by multiple columns -- 3. Set up proper backup and retention policies